  ss -plntu | grep -P -- ":${p}\b" | grep -Pvq -- "\h+(127\.0\.0\.1|\[?::1\]?):${p}\b" && { echo FAIL; exit 1; };
done; if command -v postconf >/dev/null 2>&1; then
  postconf -n inet_interfaces 2>/dev/null | grep -Pqi "\ball\b" && { echo FAIL; exit 1; };
